// Meta sends: GET ?hub.mode=subscribe&hub.verify_token=YOUR_TOKEN&hub.challenge=RANDOM
// We must respond with the hub.challenge value

const query = $input.first().json.query || {};
const verifyToken = process.env.META_VERIFY_TOKEN || 'your_verify_token_here';

if (query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === verifyToken) {
  return [{ json: { challenge: query['hub.challenge'], verified: true } }];
}

// Invalid token — return empty challenge (n8n will still respond 200, just with no body)
return [{ json: { challenge: '', verified: false, error: 'Invalid verify_token' } }];

// Parse Meta webhook payload for Instagram comment events
// Handles multiple changes per entry (batch delivery)

const body = $input.first().json.body || {};

if (!body.entry || !body.entry.length) {
  return [{ json: { valid: false, reason: 'no_entry' } }];
}

const results = [];

for (const entry of body.entry) {
  for (const change of (entry.changes || [])) {

    // We only care about 'comments' field
    if (change.field !== 'comments') continue;

    const val = change.value || {};

    // Skip deletions / edits — only process new comments
    if (val.verb && val.verb !== 'add') continue;

    // Skip replies to other comments (only process top-level comments)
    // Remove this check if you also want to trigger on replies
    if (val.parent_id) continue;

    results.push({
      json: {
        valid: true,
        platform: 'instagram',
        commentId: val.id || val.comment_id,
        commentText: (val.text || val.message || '').trim(),
        userId: (val.from && val.from.id) ? val.from.id : null,
        userName: (val.from && val.from.name) ? val.from.name : 'Unknown',
        postId: (val.media && val.media.id) ? val.media.id : (val.post_id || null),
        timestamp: val.created_time || Math.floor(Date.now() / 1000)
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { valid: false, reason: 'no_comment_events' } }];
}

return results;

// Match comment text against keyword rules from environment variable
// Set KEYWORD_RULES env var in n8n Settings → Environment Variables
// Value: the JSON array from config/rules.example.json

const input = $input.first().json;
const commentText = (input.commentText || '').toLowerCase().trim();
const platform = input.platform;

// Load rules from environment variable
let rules = [];
try {
  const raw = process.env.KEYWORD_RULES || '[]';
  rules = JSON.parse(raw);
} catch (e) {
  console.error('[keyword-matcher] Failed to parse KEYWORD_RULES env var:', e.message);
  return [{ json: { ...input, hasMatch: false, error: 'rules_parse_error' } }];
}

// Filter: active rules for this platform
const now = new Date();
const staticData = $getWorkflowStaticData('global');
const sendCounts = staticData.sendCounts || {};

const activeRules = rules.filter(rule => {
  if (!rule.active) return false;
  if (rule.platform !== platform) return false;
  if (rule.expires_at && new Date(rule.expires_at) < now) return false;
  if (rule.max_dm_sends != null && (sendCounts[rule.id] || 0) >= rule.max_dm_sends) return false;
  return true;
});

// Try to match — first match wins
let matchedRule = null;
for (const rule of activeRules) {
  const keyword = (rule.keyword || '').toLowerCase().trim();
  const matchType = rule.match_type || 'contains';

  let isMatch = false;
  switch (matchType) {
    case 'exact':
      isMatch = commentText === keyword;
      break;
    case 'starts_with':
      isMatch = commentText.startsWith(keyword);
      break;
    case 'word':
      // Full word match (not substring of another word)
      isMatch = new RegExp('\\b' + keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b').test(commentText);
      break;
    default: // 'contains'
      isMatch = commentText.includes(keyword);
  }

  if (isMatch) {
    matchedRule = rule;
    break;
  }
}

if (!matchedRule) {
  return [{ json: { ...input, hasMatch: false } }];
}

// Build the DM message from the template
let dmMessage = matchedRule.dm_message || '';
dmMessage = dmMessage.replace(/\{\{event_link\}\}/g, matchedRule.event_link || '');
dmMessage = dmMessage.replace(/\{\{event_name\}\}/g, matchedRule.event_name || '');

return [{ json: { ...input, hasMatch: true, matchedRule, dmMessage } }];

// Check if we already sent a DM to this user for this keyword (duplicate prevention)
// Uses n8n's workflow static data — persists between executions

const input = $input.first().json;
const { userId, matchedRule, platform } = input;

const staticData = $getWorkflowStaticData('global');
const dmHistory = staticData.dmHistory || {};

// Key: platform + userId + keyword — prevents spam per user per event
const cooldownKey = `${platform}_${userId}_${matchedRule.keyword}`;
const cooldownMs = (matchedRule.cooldown_hours || 720) * 60 * 60 * 1000;
const now = Date.now();
const lastSent = dmHistory[cooldownKey];

const inCooldown = !!(lastSent && (now - lastSent) < cooldownMs);
const hoursRemaining = inCooldown
  ? Math.ceil((cooldownMs - (now - lastSent)) / 3600000)
  : 0;

return [{
  json: {
    ...input,
    shouldSend: !inCooldown,
    cooldownKey,
    inCooldown,
    hoursRemaining,
    lastSent: lastSent ? new Date(lastSent).toISOString() : null
  }
}];

// Update analytics and mark DM as sent in cooldown history
// Uses n8n workflow static data (persists between executions)

// Get the original comment data (always from Check DM Cooldown node)
const data = $('Check DM Cooldown').first().json;
const { cooldownKey, matchedRule, userId, commentId, commentText, platform } = data;

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

// 1. Mark DM as sent (enforces cooldown on next comment from same user)
if (!staticData.dmHistory) staticData.dmHistory = {};
staticData.dmHistory[cooldownKey] = now;

// 2. Increment send count for max_dm_sends enforcement
if (!staticData.sendCounts) staticData.sendCounts = {};
staticData.sendCounts[matchedRule.id] = (staticData.sendCounts[matchedRule.id] || 0) + 1;

// 3. Keyword-level analytics
if (!staticData.analytics) staticData.analytics = {};
const analyticsKey = `${platform}_${matchedRule.keyword}`;

if (!staticData.analytics[analyticsKey]) {
  staticData.analytics[analyticsKey] = {
    keyword: matchedRule.keyword,
    platform,
    eventName: matchedRule.event_name || '',
    totalSent: 0,
    firstSent: new Date(now).toISOString(),
    lastSent: null,
    recentSends: []
  };
}

const stats = staticData.analytics[analyticsKey];
stats.totalSent += 1;
stats.lastSent = new Date(now).toISOString();

// Keep last 50 sends for audit trail
stats.recentSends.unshift({
  userId,
  commentId,
  commentPreview: (commentText || '').substring(0, 80),
  sentAt: new Date(now).toISOString()
});
stats.recentSends = stats.recentSends.slice(0, 50);

return [{
  json: {
    success: true,
    platform,
    ruleId: matchedRule.id,
    keyword: matchedRule.keyword,
    eventName: matchedRule.event_name,
    userId,
    commentId,
    totalSentForKeyword: stats.totalSent,
    sentAt: new Date(now).toISOString()
  }
}];
